DROP TABLE IF EXISTS `vista_apostapremis`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_apostapremis`  AS SELECT `a`.`coJugador` AS `coJugador`, `a`.`idPremi` AS `idPremi`, `a`.`idEquip` AS `idEquip`, `e`.`coEquip` AS `coEquip`, (case when ((`pe`.`idEquip` = 0) or (`p`.`dtPremi` > curdate())) then NULL else (case when ((`pe`.`idEquip` is not null) and (`pe`.`idEquip` = `a`.`idEquip`)) then 1 else 0 end) end) AS `isPremi`, (case when ((`pe`.`idEquip` = 0) or (`p`.`dtPremi` > curdate())) then NULL else (case when ((`pe`.`idEquip` is not null) and (`pe`.`idEquip` = `a`.`idEquip`)) then `p`.`Puntuacio` else 0 end) end) AS `Punts`, `e`.`vcNom` AS `vcNom`, `e`.`vcLogo` AS `vcLogo`, `p`.`dtPremi` AS `dtPremi`, `e2`.`vcLogo` AS `logoEQ`, `e2`.`vcNom` AS `NomEQ`, `e2`.`idEquip` AS `IdEQ`, `p`.`Nom` AS `Nom`, `p`.`Puntuacio` AS `Puntuacio`, `p`.`idFase` AS `idFase`, `p`.`idGrup` AS `idGrup`, `total`.`quants` AS `Quants` FROM ((((((`premis` `p` left join `apostapremis` `a` on((`p`.`idPremi` = `a`.`idPremi`))) left join `equips` `e` on((`a`.`idEquip` = `e`.`idEquip`))) left join `premisequips` `pe` on((`p`.`idPremi` = `pe`.`idPremi`))) left join `equips` `e2` on((`pe`.`idEquip` = `e2`.`idEquip`))) left join (select `premisequips`.`idPremi` AS `idPremi`,count(0) AS `quants` from `premisequips` group by `premisequips`.`idPremi`) `total` on((`p`.`idPremi` = `total`.`idPremi`))) join `jugadors` `jj` on((`a`.`coJugador` = `jj`.`coJugador`))) WHERE ((`jj`.`Actiu` = 1) AND (`p`.`Actiu` = 1)) ORDER BY `p`.`Ordre` ASC, (case when ((`pe`.`idEquip` is null) or (`p`.`dtPremi` > curdate())) then NULL else (case when ((`pe`.`idEquip` is not null) and (`pe`.`idEquip` = `a`.`idEquip`)) then 1 else 0 end) end) ASC ;

