CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_clasificacion`  AS SELECT `jj`.`coJugador` AS `coJugador`, `jj`.`Nom` AS `NomJugador`, `jj`.`Nickname` AS `Nickname`, `jj`.`Avatar` AS `Avatar`, `copesencertp`.`cojugador` AS `coJugadorP1`, `copesencertp`.`Cuenta1` AS `P1`, `copesencertp`.`Puntos1` AS `PuntosP1`, `copesencertp`.`Cuenta2` AS `P2`, `copesencertp`.`Puntos2` AS `PuntosP2`, `copesencertp`.`Cuenta3` AS `P3`, `copesencertp`.`Puntos3` AS `PuntosP3`, `copesencertp`.`Cuenta5` AS `P5`, `copesencertp`.`Puntos5` AS `PuntosP5`, `copesencertp`.`Cuenta6` AS `P6`, `copesencertp`.`Puntos6` AS `PuntosP6`, `copesencertp`.`Cuenta7` AS `P7`, `copesencertp`.`Puntos7` AS `PuntosP7`, (case when (`copespremis`.`Puntos` is null) then 0 else `copespremis`.`Puntos` end) AS `PuntosPremis`, (case when (`copesporcentaje`.`Puntos` is null) then 0 else `copesporcentaje`.`Puntos` end) AS `PuntosPorcentaje`, (((((((`copesencertp`.`Puntos1` + `copesencertp`.`Puntos2`) + `copesencertp`.`Puntos3`) + `copesencertp`.`Puntos5`) + `copesencertp`.`Puntos6`) + `copesencertp`.`Puntos7`) + (case when (`copespremis`.`Puntos` is null) then 0 else `copespremis`.`Puntos` end)) + (case when (`copesporcentaje`.`Puntos` is null) then 0 else `copesporcentaje`.`Puntos` end)) AS `Puntuacio` FROM (((`jugadors` `jj` left join (select `vista_punts_x_partit`.`coJugador` AS `cojugador`,sum((case when (`vista_punts_x_partit`.`idEncert` = 1) then `vista_punts_x_partit`.`Punts` else 0 end)) AS `Puntos1`,sum((case when (`vista_punts_x_partit`.`idEncert` = 1) then 1 else 0 end)) AS `Cuenta1`,sum((case when (`vista_punts_x_partit`.`idEncert` = 2) then `vista_punts_x_partit`.`Punts` else 0 end)) AS `Puntos2`,sum((case when (`vista_punts_x_partit`.`idEncert` = 2) then 1 else 0 end)) AS `Cuenta2`,sum((case when (`vista_punts_x_partit`.`idEncert` = 3) then `vista_punts_x_partit`.`Punts` else 0 end)) AS `Puntos3`,sum((case when (`vista_punts_x_partit`.`idEncert` = 3) then 1 else 0 end)) AS `Cuenta3`,sum((case when (`vista_punts_x_partit`.`idEncert` = 5) then `vista_punts_x_partit`.`Punts` else 0 end)) AS `Puntos5`,sum((case when (`vista_punts_x_partit`.`idEncert` = 5) then 1 else 0 end)) AS `Cuenta5`,sum((case when (`vista_punts_x_partit`.`idEncert` = 6) then `vista_punts_x_partit`.`Punts` else 0 end)) AS `Puntos6`,sum((case when (`vista_punts_x_partit`.`idEncert` = 6) then 1 else 0 end)) AS `Cuenta6`,sum((case when (`vista_punts_x_partit`.`idEncert` = 7) then `vista_punts_x_partit`.`Punts` else 0 end)) AS `Puntos7`,sum((case when (`vista_punts_x_partit`.`idEncert` = 7) then 1 else 0 end)) AS `Cuenta7`,count(0) AS `Cuenta`,sum(`vista_punts_x_partit`.`Punts`) AS `Puntos` from `vista_punts_x_partit` group by `vista_punts_x_partit`.`coJugador`) `copesencertp` on((`jj`.`coJugador` = `copesencertp`.`cojugador`))) left join (select `vista_punts_x_premi`.`coJugador` AS `cojugador`,sum(`vista_punts_x_premi`.`Punts`) AS `Puntos` from `vista_punts_x_premi` group by `vista_punts_x_premi`.`coJugador`) `copespremis` on((`copesencertp`.`cojugador` = `copespremis`.`cojugador`))) left join (select `vista_punts_x_porcentaje`.`coJugador` AS `cojugador`,sum(`vista_punts_x_porcentaje`.`punts`) AS `Puntos` from `vista_punts_x_porcentaje` group by `vista_punts_x_porcentaje`.`coJugador`) `copesporcentaje` on((`copesencertp`.`cojugador` = `copesporcentaje`.`cojugador`))) WHERE (`jj`.`Actiu` = 1) ;

