CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`%` SQL SECURITY DEFINER VIEW `vista_estadistiques_x_equip`  AS SELECT `EQ`.`vcLogo` AS `logo`, `EQ`.`vcNom` AS `vcNom`, `Estadisticas`.`coEquip` AS `coEquip`, sum(`Estadisticas`.`PartidosJugados`) AS `PartidosJugados`, sum(`Estadisticas`.`Victoria`) AS `Victoria`, sum(`Estadisticas`.`Empate`) AS `Empate`, sum(`Estadisticas`.`Derrota`) AS `Derrota`, sum(`Estadisticas`.`GolesFavor`) AS `GolesFavor`, sum(`Estadisticas`.`GolesContra`) AS `GolesContra` FROM ((select 'local' AS `T`,`e1`.`coEquip` AS `coEquip`,count(0) AS `PartidosJugados`,sum((case when (`p`.`Resultat1` > `p`.`Resultat2`) then 1 else 0 end)) AS `Victoria`,sum((case when (`p`.`Resultat1` = `p`.`Resultat2`) then 1 else 0 end)) AS `Empate`,sum((case when (`p`.`Resultat1` < `p`.`Resultat2`) then 1 else 0 end)) AS `Derrota`,sum(`p`.`Resultat1`) AS `GolesFavor`,sum(`p`.`Resultat2`) AS `GolesContra` from (`partits` `p` left join `equips` `e1` on((`p`.`Equip1` = `e1`.`coEquip`))) where ((`p`.`Resultat1` is not null) and (`p`.`Resultat2` is not null)) group by `e1`.`coEquip` union select 'visitant' AS `T`,`e2`.`coEquip` AS `coEquip`,count(0) AS `PartidosJugados`,sum((case when (`p`.`Resultat1` < `p`.`Resultat2`) then 1 else 0 end)) AS `Victoria`,sum((case when (`p`.`Resultat1` = `p`.`Resultat2`) then 1 else 0 end)) AS `Empate`,sum((case when (`p`.`Resultat1` > `p`.`Resultat2`) then 1 else 0 end)) AS `Derrota`,sum(`p`.`Resultat2`) AS `GolesFavor`,sum(`p`.`Resultat1`) AS `GolesContra` from (`partits` `p` left join `equips` `e2` on((`p`.`Equip2` = `e2`.`coEquip`))) where ((`p`.`Resultat1` is not null) and (`p`.`Resultat2` is not null)) group by `e2`.`coEquip`) `Estadisticas` join `equips` `EQ` on((`Estadisticas`.`coEquip` = `EQ`.`coEquip`))) GROUP BY `Estadisticas`.`coEquip` ;

