CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_porcentajes`  AS SELECT `porcentajesapuestas`.`prono` AS `prono`, `porcentajesapuestas`.`count(*)` AS `numero`, `porcentajesapuestas`.`idpartit` AS `idpartit`, `porcentajesapuestas`.`total` AS `total`, `porcentajesapuestas`.`porcen` AS `porcen`, `porcentajesapuestas`.`porcentaje` AS `porcentaje`, `pes`.`idporcentaje` AS `idporcentaje`, `pes`.`desde` AS `desde`, `pes`.`hasta` AS `hasta`, `pes`.`puntos` AS `puntos`, truncate(`porcentajesapuestas`.`porcentaje`,2) AS `PorcentajeFinal`, `partits`.`Equip1` AS `Equip1`, `partits`.`Equip2` AS `Equip2`, (case when (`porcentajesapuestas`.`prono` = 'victoria') then concat('Victoria ',`e1`.`vcNom`) when (`porcentajesapuestas`.`prono` = 'derrota') then concat('Victoria ',`e2`.`vcNom`) else convert(`porcentajesapuestas`.`prono` using utf8mb3) end) AS `Desc` FROM (((((select `apuestas`.`prono` AS `prono`,`apuestas`.`count(*)` AS `count(*)`,`apuestas`.`idpartit` AS `idpartit`,`apuestas`.`total` AS `total`,`apuestas`.`porcen` AS `porcen`,(case when (`apuestas`.`prono` = 'No Apostado') then 102 else `apuestas`.`porcen` end) AS `porcentaje` from (select (case when (`a`.`Resultat1` = `a`.`Resultat2`) then 'Empate' when (`a`.`Resultat1` > `a`.`Resultat2`) then 'Victoria' when (`a`.`Resultat1` < `a`.`Resultat2`) then 'Derrota' else 'No Apostado' end) AS `prono`,count(0) AS `count(*)`,`a`.`idPartit` AS `idpartit`,`total`.`total` AS `total`,((count(0) / `total`.`total`) * 100) AS `porcen` from ((`apostapartits` `a` left join (select `aa`.`idPartit` AS `Idpartit`,count(0) AS `total` from (`apostapartits` `aa` join `jugadors` `j` on(((`aa`.`coJugador` = `j`.`coJugador`) and (`j`.`Actiu` = 1)))) group by `aa`.`idPartit`) `total` on((`a`.`idPartit` = `total`.`Idpartit`))) join `jugadors` `j` on(((`a`.`coJugador` = `j`.`coJugador`) and (`j`.`Actiu` = 1)))) group by (case when (`a`.`Resultat1` = `a`.`Resultat2`) then 'Empate' when (`a`.`Resultat1` > `a`.`Resultat2`) then 'Victoria' when (`a`.`Resultat1` < `a`.`Resultat2`) then 'Derrota' else 'No Apostado' end),`a`.`idPartit`) `apuestas`) `porcentajesapuestas` left join `porcentajes` `pes` on(((`porcentajesapuestas`.`porcentaje` > `pes`.`desde`) and (`porcentajesapuestas`.`porcentaje` <= `pes`.`hasta`)))) left join `partits` on((`porcentajesapuestas`.`idpartit` = `partits`.`idPartit`))) left join `equips` `e1` on((`partits`.`Equip1` = `e1`.`coEquip`))) left join `equips` `e2` on((`partits`.`Equip2` = `e2`.`coEquip`))) ORDER BY `porcentajesapuestas`.`idpartit` ASC, `porcentajesapuestas`.`prono` ASC ;

