DROP TABLE IF EXISTS `vista_punts_x_jugador`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_punts_x_jugador`  AS SELECT `puntuaciojugadors`.`coJugador` AS `coJugador`, `jj`.`Nom` AS `NomJugador`, `jj`.`Nickname` AS `Nickname`, `jj`.`Avatar` AS `Avatar`, sum(`puntuaciojugadors`.`P`) AS `Puntuacio` FROM ((select `vista_punts_x_premi`.`coJugador` AS `coJugador`,sum(`vista_punts_x_premi`.`Punts`) AS `P` from `vista_punts_x_premi` group by `vista_punts_x_premi`.`coJugador` union select `vista_punts_x_partit`.`coJugador` AS `coJugador`,sum(`vista_punts_x_partit`.`Punts`) AS `P` from `vista_punts_x_partit` group by `vista_punts_x_partit`.`coJugador` union select `vista_punts_x_porcentaje`.`coJugador` AS `coJugador`,sum(`vista_punts_x_porcentaje`.`punts`) AS `P` from `vista_punts_x_porcentaje` group by `vista_punts_x_porcentaje`.`coJugador`) `puntuaciojugadors` join `jugadors` `jj` on((`puntuaciojugadors`.`coJugador` = `jj`.`coJugador`))) WHERE (`jj`.`Actiu` = 1) GROUP BY `puntuaciojugadors`.`coJugador`, `jj`.`Nom` ORDER BY sum(`puntuaciojugadors`.`P`) DESC, `puntuaciojugadors`.`coJugador` ASC ;

