DROP TABLE IF EXISTS `vista_punts_x_partit`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_punts_x_partit`  AS SELECT `apostes`.`coJugador` AS `coJugador`, `apostes`.`idPartit` AS `idPartit`, `apostes`.`Resultat1` AS `Resultat1`, `apostes`.`Resultat2` AS `Resultat2`, `apostes`.`idEncert` AS `idEncert`, `ttencerts`.`Encert` AS `Encert`, `ttencerts`.`Punts` AS `Punts` FROM ((select `a`.`coJugador` AS `coJugador`,`a`.`idPartit` AS `idPartit`,`a`.`Resultat1` AS `Resultat1`,`a`.`Resultat2` AS `Resultat2`,(case when ((`p`.`Resultat1` = `a`.`Resultat1`) and (`p`.`Resultat2` = `a`.`Resultat2`)) then (case when (`p`.`Fase` = 1) then 1 else 5 end) else (case when (((`p`.`Resultat1` = `a`.`Resultat1`) or (`p`.`Resultat2` = `a`.`Resultat2`)) and (((`p`.`Resultat1` > `p`.`Resultat2`) and (`a`.`Resultat1` > `a`.`Resultat2`)) or ((`p`.`Resultat1` < `p`.`Resultat2`) and (`a`.`Resultat1` < `a`.`Resultat2`)) or ((`p`.`Resultat1` = `p`.`Resultat2`) and (`a`.`Resultat1` = `a`.`Resultat2`)))) then (case when (`p`.`Fase` = 1) then 2 else 6 end) else (case when ((`p`.`Resultat1` <> `a`.`Resultat1`) and (`p`.`Resultat2` <> `a`.`Resultat2`) and (((`p`.`Resultat1` > `p`.`Resultat2`) and (`a`.`Resultat1` > `a`.`Resultat2`)) or ((`p`.`Resultat1` < `p`.`Resultat2`) and (`a`.`Resultat1` < `a`.`Resultat2`)) or ((`p`.`Resultat1` = `p`.`Resultat2`) and (`a`.`Resultat1` = `a`.`Resultat2`)))) then (case when (`p`.`Fase` = 1) then 3 else 7 end) else 4 end) end) end) AS `idEncert` from (`partits` `p` left join `apostapartits` `a` on((`p`.`idPartit` = `a`.`idPartit`)))) `apostes` join `ttencerts` on((`apostes`.`idEncert` = `ttencerts`.`idEncert`))) ;

