DROP TABLE IF EXISTS `vista_punts_x_porcentaje`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_punts_x_porcentaje`  AS SELECT `pronosjugadores`.`coJugador` AS `coJugador`, `pronosjugadores`.`idPartit` AS `idPartit`, `pronosjugadores`.`PronosticoJugador` AS `PronosticoJugador`, `por`.`PorcentajeFinal` AS `porcentajefinal`, (case when (`par`.`idEncert` <> 4) then `por`.`puntos` else 0 end) AS `punts` FROM (((select `a`.`coJugador` AS `coJugador`,`a`.`idPartit` AS `idPartit`,(case when (`a`.`Resultat1` > `a`.`Resultat2`) then 'victoria' when (`a`.`Resultat1` = `a`.`Resultat2`) then 'empate' when (`a`.`Resultat1` < `a`.`Resultat2`) then 'derrota' when (`a`.`Resultat1` is null) then 'nulo' end) AS `PronosticoJugador` from `apostapartits` `a`) `pronosjugadores` left join `vista_porcentajes` `por` on(((`pronosjugadores`.`PronosticoJugador` = `por`.`prono`) and (`pronosjugadores`.`idPartit` = `por`.`idpartit`)))) left join `vista_punts_x_partit` `par` on(((`pronosjugadores`.`coJugador` = `par`.`coJugador`) and (`pronosjugadores`.`idPartit` = `par`.`idPartit`)))) ;

