CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_punts_x_premi`  AS SELECT `a`.`coJugador` AS `coJugador`, `p`.`idPremi` AS `idPremi`, (case when (`pe`.`idEquip` is not null) then 1 else 0 end) AS `isPremi`, (case when (`pe`.`idEquip` is not null) then `p`.`Puntuacio` else 0 end) AS `Punts` FROM ((`premis` `p` left join `apostapremis` `a` on((`p`.`idPremi` = `a`.`idPremi`))) left join `premisequips` `pe` on(((`p`.`idPremi` = `pe`.`idPremi`) and (`a`.`idEquip` = `pe`.`idEquip`)))) ;

